#ifdef __cplusplus
extern "C" {
#endif

#define fp double

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    __global box_str* box,
    __global FOUR_VECTOR* rv,
    __global fp* qv,
    __global FOUR_VECTOR* fv)
{
    int l = get_global_id(0) / NUMBER_PAR_PER_BOX;
    int local_id = get_global_id(0) % NUMBER_PAR_PER_BOX;

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    int i = local_id;

    FOUR_VECTOR rA_i = rA[i];
    FOUR_VECTOR fA_i = {0.0, 0.0, 0.0, 0.0};

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            FOUR_VECTOR rB_j = rB[j];
            fp qB_j = qB[j];

            fp r2 = rA_i.v + rB_j.v - DOT(rA_i, rB_j);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rA_i.x - rB_j.x;
            d.y = rA_i.y - rB_j.y;
            d.z = rA_i.z - rB_j.z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fA_i.v += qB_j * vij;
            fA_i.x += qB_j * fxij;
            fA_i.y += qB_j * fyij;
            fA_i.z += qB_j * fzij;
        }
    }

    fA[i] = fA_i;
}

#ifdef __cplusplus
}
#endif
